INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('d56e7baf-34d4-5ca5-aea5-1a89724b9960', '04f35b63-f5dd-4b18-832c-a88c25943a0a', 'The sunrise will occur at approximately 5:45 ___.', '日出大約會在上午五點四十五分發生。', 'a.m.', 'daily', 'regularly', 'often', 'ante (在...之前) + meridiem (中午)', 'a.m. 來自拉丁文 ante meridiem，意為中午之前 → 上午。', '2026-07-06 15:50:06', '2026-07-06 15:50:06'),
('f1226a42-2b0f-5bff-ac05-f974b227ad90', '24621e09-337c-401f-beb2-59bd4e56a432', 'Even though he speaks English fluently, he still has a strong French ___.', '即便他英語說得很流利，他仍帶有強烈的法國腔調。', 'accent', 'rhythm', 'volume', 'pitch', 'accent 源自拉丁語 accentus，意指「吟唱」或「強調」。在語言學中，指說話時的腔調或單字的重音。', '想像說話時，某些字會被特別「強調」出來，這種強調的口音就是 accent。', '2026-07-06 16:37:28', '2026-07-06 16:37:28'),
('afd8e45f-863a-52c8-a660-96a78d58748c', '0c81c4d7-077d-46ec-b6bc-a975304fa7ad', 'A new bridge was constructed to help commuters drive ___ the wide river.', '一座新橋的建成是為了幫助通勤者橫越寬闊的河流。', 'across', 'along', 'toward', 'beneath', 'cross (十字/橫越) + a- (在...之上) → across (橫跨/遍及)', '想像一個十字路口 (cross)，從一邊穿過到另一邊就是 across。', '2026-07-06 17:20:36', '2026-07-06 17:20:36'),
('d5596467-b96d-504b-a826-ac1914c4b698', '231026ab-acab-472b-a396-92556260d8db', 'The runner finished the race, and the crowd cheered shortly ___.', '跑者跑完了比賽，群眾隨即發出歡呼。', 'after', 'away', 'back', 'fast', 'after 作為副詞時，表示「隨後」或「在後」。', 'shortly after → 很快地在之後 → 隨即。', '2026-07-06 18:44:54', '2026-07-06 18:44:54'),
('83b215f6-09ca-5fbf-8b3a-98a1544b1108', '5af8fc1a-08ef-4e14-ab59-414976771444', 'The magician''s incredible performance continued to ___ the audience throughout the evening.', '魔術師那令人難以置信的表演在整個晚上持續讓觀眾感到大為驚奇。', 'amaze', 'annoy', 'satisfy', 'frighten', 'a- (趨向/使) + maze (迷宮/困惑) → 使人陷入迷宮般的困惑狀態 → 使大為驚奇', '想像你在迷宮 maze 中迷路了，那種不知所措的感覺就像是被驚奇到了。', '2026-07-06 20:34:47', '2026-07-06 20:34:47'),
('d5933977-bdfe-5771-ba1f-9f6f6739d8dc', '8cbde552-85ad-45f5-a68e-5de703f2b65a', 'After the accident, the ___ arrived quickly to take the injured man to the hospital.', '事故發生後，救護車迅速趕到，將傷者送往醫院。', 'ambulance', 'bus', 'truck', 'train', 'ambul- (源自拉丁語 ambulare) → 意思是「行走」或「移動」。', '想像救護車在街上不斷「移動」去救人的樣子。', '2026-07-06 14:00:01', '2026-07-06 14:00:01'),
('f4f8d151-fa8d-5e1e-943b-9d7538a1afd4', '17f80d9b-5319-48ab-b6bb-5b5a7dcea383', 'The scientist''s theory was based on the false ___ that the temperature remained constant throughout the experiment.', '這位科學家的理論是建立在實驗過程中溫度保持不變的錯誤假設之上。', 'assumption', 'conclusion', 'solution', 'tradition', 'root: assum (拿/取) + suffix: -tion (名詞字尾) → 拿取一個未經證實的事實 → 假設', '想像你隨手「拿 (sume)」起一個想法當作事實，但其實還沒證實，這就是 assumption (假設)。', '2026-07-07 01:30:43', '2026-07-07 01:30:43'),
('fae3537b-6122-5f78-a7be-6d9b5f5ef364', 'bb56a3e8-f551-4c89-b587-8f5e9bae4654', 'She was happy ___ she passed the English test.', '她很高興，因為她通過了英文考試。', 'because', 'unless', 'when', 'until', 'because 由 be + cause (造成) 組成，字面意思是「造成...的原因」。', '因為考得好 → 所以很開心。記住 because 後面接原因。', '2026-07-07 02:51:02', '2026-07-07 02:51:02'),
('fd86f8eb-e6ab-565b-8d70-b3e4f7a763b0', '2b34c4a1-92c2-4f97-b7dc-f4b96b129cf0', 'We are going to have a party for Tim''s ___ next Saturday.', '我們下週六要為提姆的生日舉辦一個派對。', 'birthday', 'lesson', 'movie', 'game', '由 birth (出生) 與 day (天/日子) 組成的複合名詞。', '想像出生 (birth) 的那一天 (day) 要慶祝，就是 birthday。', '2026-07-07 03:45:52', '2026-07-07 03:45:52'),
('8816a6a2-ed3b-55eb-bce8-40cf092d9c7c', '250b68d8-8eea-4c85-83fb-eeecddc54f2f', 'The dog''s favorite ___ is white and hard.', '這隻狗最喜歡的骨頭是白色且堅硬的。', 'bone', 'ball', 'shoe', 'cup', 'bone 為單音節名詞，指身體的硬組織或骨頭。', '想像小狗正在啃一根白色的 bone (骨頭)。', '2026-07-07 05:02:16', '2026-07-07 05:02:16'),
('86e3c0b0-0937-59ce-8dde-ad0980b77bb4', '930293e1-a73a-4859-a392-243e56a80df0', 'The baby was ___ in a hospital last night.', '那個嬰兒昨晚在醫院出生。', 'born', 'lost', 'kept', 'found', '源自動詞 bear (出生) → born (出生的) 的過去分詞形式。', '記住 be born 是「出生」的固定用法。', '2026-07-07 05:12:02', '2026-07-07 05:12:02'),
('63a015b3-c414-5080-8341-8941aefb8c4c', '3acd6dc0-ea51-4af6-8052-f6a13ec49df3', 'The sun shines brightly during the ___.', '太陽在白天明亮地照耀。', 'day', 'night', 'week', 'year', 'day 指的是一日或白天的時間單位。', '太陽升起的那一天就是 day。', '2026-07-07 02:53:54', '2026-07-07 02:53:54'),
('82a0be48-4cc7-5049-9310-3cb41c4f0458', '32379e4a-ed83-4dce-8c13-d6c091569ef7', 'I want to try a ___ kind of food this weekend.', '我這週末想嘗試一種不同的食物。', 'different', 'tasty', 'heavy', 'cheap', 'differ (不同) + -ent (形容詞字尾) → 不同的', '想像你想換個口味，找「不同」的食物，就是 different。', '2026-07-07 04:02:09', '2026-07-07 04:02:09'),
('48f5cde5-9dc3-58e7-8631-4c1e52495d58', 'c9513137-988a-4a5b-9c63-e3c19f5a7504', 'The ___ car is very quiet and good for the environment.', '這輛電動汽車非常安靜，而且對環境很好。', 'electric', 'hungry', 'careful', 'famous', '字根 electr- 代表「電」。', 'electr + ic (形容詞字尾) → 電的。可以聯想 electric guitar (電吉他) 或 electric fan (電風扇)。', '2026-07-07 03:34:58', '2026-07-07 03:34:58'),
('9d61727a-82dc-5b42-94e4-169749eb22b8', '9b0ed757-efa4-44bd-a551-799d1d3f0d4c', 'The ___ little boy can play soccer for two hours without feeling tired.', '這個精力充沛的小男孩可以踢兩小時足球而不覺得累。', 'energetic', 'hungry', 'sleepy', 'angry', 'energy (能量) + -tic (形容詞字尾) → energetic (精力充沛的)', '想像一個充滿 energy (能量) 的人，動作停不下來 → energetic (精力充沛的)', '2026-07-07 03:50:06', '2026-07-07 03:50:06'),
('ce476774-f9c3-5ab2-9d94-e01b1d105648', '8e57d228-2375-4684-9b15-7e73584141b6', 'I hope to ___ a high score on the English test.', '我希望能在英文考試中拿到高分。', 'get', 'make', 'take', 'see', '表示「得到」或「拿到」的意思。', 'Get it! (拿到它)', '2026-07-05 07:16:15', '2026-07-05 07:16:15'),
('7f91550e-8b41-5de3-bbb2-8ba6e1948e84', '056bbf79-2f62-44e1-88e9-19e796ece41a', 'The company ___ launch a new product line to compete with its rivals next month.', '這間公司將於下個月推出新產品線以與競爭對手競爭。', 'will', 'must', 'can', 'may', '助動詞，用於表示未來或計畫。', 'will → 將會 (助動詞用法)', '2026-07-05 14:40:20', '2026-07-05 14:40:20');
